#include <vector>
#include <algorithm>

void gnomeSort(std::vector<int>& arr) {
    int n = arr.size();
    int pos = 0;
    while (pos < n) {
        if (pos == 0 || arr[pos] >= arr[pos - 1]) {
            pos++;
        } else {
            std::swap(arr[pos], arr[pos - 1]);
            pos--;
        }
    }
}

