public class GnomeSort {
    public static void sort(int[] arr) {
        int pos = 0;
        while (pos < arr.length) {
            if (pos == 0 || arr[pos] >= arr[pos - 1]) {
                pos++;
            } else {
                int temp = arr[pos];
                arr[pos] = arr[pos - 1];
                arr[pos - 1] = temp;
                pos--;
            }
        }
    }
}
